    // ── SMART HOME ОБЩЕЕ ──
    smart_device_scan: tool({
      description: "\u0421\u043A\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u0442\u044C \u0441\u0435\u0442\u044C \u043D\u0430 \u0443\u043C\u043D\u044B\u0435 \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430 (UPnP/SSDP).",
      inputSchema: external_exports.object({}),
      execute: async () => {
        try {
          const dgram = await import("node:dgram");
          const socket = dgram.createSocket("udp4");
          const msg = [
            "M-SEARCH * HTTP/1.1",
            "HOST: 239.255.255.250:1900",
            'MAN: "ssdp:discover"',
            "ST: ssdp:all",
            "MX: 3",
            "",
            ""
          ].join("\r\n");
          return new Promise((resolve2) => {
            const found = [];
            const seen = /* @__PURE__ */ new Set();
            socket.on("message", (buf, rinfo) => {
              if (seen.has(rinfo.address)) return;
              seen.add(rinfo.address);
              const data = buf.toString();
              const stMatch = data.match(/ST:\s*(.*)/i);
              const serverMatch = data.match(/Server:\s*(.*)/i);
              found.push({
                ip: rinfo.address,
                type: stMatch?.[1]?.trim() || "unknown",
                server: serverMatch?.[1]?.trim() || "unknown"
              });
            });
            socket.send(msg, 1900, "239.255.255.250");
            setTimeout(() => {
              socket.close();
              resolve2({ devices: found, total: found.length });
            }, 4e3);
          });
        } catch (e) {
          return { error: `\u041E\u0448\u0438\u0431\u043A\u0430 \u0441\u043A\u0430\u043D\u0438\u0440\u043E\u0432\u0430\u043D\u0438\u044F: ${e.message}` };
        }
      }
    }),
    smart_light_control: tool({
      description: "\u0423\u043F\u0440\u0430\u0432\u043B\u0435\u043D\u0438\u0435 \u0443\u043C\u043D\u044B\u043C\u0438 \u043B\u0430\u043C\u043F\u0430\u043C\u0438 (Hue, Yeelight, TP-Link).",
      inputSchema: external_exports.object({
        brand: external_exports.string().describe("\u0411\u0440\u0435\u043D\u0434: hue, yeelight, tplink"),
        ip: external_exports.string().optional().describe("IP \u043B\u0430\u043C\u043F\u044B"),
        command: external_exports.string().describe("\u041A\u043E\u043C\u0430\u043D\u0434\u0430: on, off, dim, color, scene"),
        value: external_exports.string().optional().describe("\u0417\u043D\u0430\u0447\u0435\u043D\u0438\u0435 (0-100 \u0434\u043B\u044F \u044F\u0440\u043A\u043E\u0441\u0442\u0438, hex \u0434\u043B\u044F \u0446\u0432\u0435\u0442\u0430)")
      }),
      execute: async ({ brand, ip, command: command2, value }) => {
        try {
          if (brand === "yeelight") {
            const cmd = {
              on: '{"id":1,"method":"set_power","params":["on","smooth",500]}',
              off: '{"id":1,"method":"set_power","params":["off","smooth",500]}',
              dim: `{"id":1,"method":"set_bright","params":[${value || 50},"smooth",500]}`,
              color: `{"id":1,"method":"set_rgb","params":[${parseInt(value || "16777215", 16)},"smooth",500]}`
            };
            const net = await import("node:net");
            return new Promise((resolve2) => {
              const client = net.createConnection({ port: 55443, host: ip }, () => {
                client.write(cmd[command2] || cmd.on + "\r\n");
              });
              client.on("data", (data) => {
                client.destroy();
                resolve2({ success: true, response: data.toString() });
              });
              client.on("error", (e) => {
                resolve2({ error: `Yeelight \u043E\u0448\u0438\u0431\u043A\u0430: ${e.message}` });
              });
              setTimeout(() => {
                client.destroy();
                resolve2({ success: true });
              }, 3e3);
            });
          }
          if (brand === "tplink") {
            const cmd = {
              on: '{"system":{"set_relay_state":{"state":1}}}',
              off: '{"system":{"set_relay_state":{"state":0}}}'
            };
            const net = await import("node:net");
            const encrypt = (data) => {
              let key = 171;
              const buf = Buffer.alloc(data.length);
              for (let i = 0; i < data.length; i++) {
                buf[i] = key ^ data.charCodeAt(i);
                key = buf[i];
              }
              return buf;
            };
            return new Promise((resolve2) => {
              const client = net.createConnection({ port: 9999, host: ip }, () => {
                const payload = cmd[command2] || cmd.on;
                const encrypted = encrypt(payload);
                const header = Buffer.alloc(4);
                header.writeUInt32BE(encrypted.length);
                client.write(Buffer.concat([header, encrypted]));
              });
              client.on("data", () => {
                client.destroy();
                resolve2({ success: true, command: command2 });
              });
              client.on("error", (e) => {
                resolve2({ error: `TP-Link \u043E\u0448\u0438\u0431\u043A\u0430: ${e.message}` });
              });
              setTimeout(() => {
                client.destroy();
                resolve2({ success: true });
              }, 3e3);
            });
          }
          return { error: `\u0411\u0440\u0435\u043D\u0434 ${brand} \u043F\u043E\u043A\u0430 \u043D\u0435 \u043F\u043E\u0434\u0434\u0435\u0440\u0436\u0438\u0432\u0430\u0435\u0442\u0441\u044F. \u0414\u043E\u0441\u0442\u0443\u043F\u043D\u044B: yeelight, tplink` };
        } catch (e) {
          return { error: `\u041E\u0448\u0438\u0431\u043A\u0430: ${e.message}` };
        }
      }
    }),
