    // ── WAKE ON LAN ──
    wake_on_lan: tool({
      description: "\u0412\u043A\u043B\u044E\u0447\u0438\u0442\u044C \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u043E \u043F\u043E Wake-on-LAN (MAC \u0430\u0434\u0440\u0435\u0441).",
      inputSchema: external_exports.object({
        mac: external_exports.string().describe("MAC \u0430\u0434\u0440\u0435\u0441 \u0443\u0441\u0442\u0440\u043E\u0439\u0441\u0442\u0432\u0430")
      }),
      execute: async ({ mac: mac3 }) => {
        try {
          const cleanMac = mac3.replace(/[:-]/g, "");
          const magicPacket = Buffer.alloc(6 + 16 * 6, 255);
          for (let i = 0; i < 16; i++) {
            Buffer.from(cleanMac, "hex").copy(magicPacket, 6 + i * 6);
          }
          const dgram = await import("node:dgram");
          const socket = dgram.createSocket("udp4");
          return new Promise((resolve2) => {
            socket.send(magicPacket, 9, "255.255.255.255", () => {
              socket.close();
              resolve2({ success: true, mac: mac3, sent: true });
            });
          });
        } catch (e) {
          return { error: `WOL \u043E\u0448\u0438\u0431\u043A\u0430: ${e.message}` };
        }
      }
    }),
