    "#2563eb",
    "#059669",
    "#d97706",
    "#dc2626",
    "#8b5cf6",
    "#3b82f6",
    "#10b981",
    "#f59e0b",
    "#ef4444",
    "#6d28d9",
    "#1d4ed8",
    "#047857",
    "#b45309",
    "#b91c1c",
    "#a78bfa",
    "#60a5fa",
    "#34d399",
    "#fbbf24",
    "#f87171"
